import threading
import time

WATCHDOG_S = 1.0


def _run(targets):
    errors = []
    barrier = threading.Barrier(len(targets) + 1)

    def wrap(fn):
        def go():
            try:
                barrier.wait()
                fn()
            except BaseException as exc:  # noqa: BLE001 - relayed below
                errors.append(exc)
        return go

    threads = [threading.Thread(target=wrap(t), daemon=True) for t in targets]
    for t in threads:
        t.start()
    barrier.wait()
    deadline = time.monotonic() + WATCHDOG_S
    for t in threads:
        t.join(max(0.0, deadline - time.monotonic()))
    if errors:
        raise errors[0]
    if any(t.is_alive() for t in threads):
        raise RuntimeError(
            "threads did not finish within the watchdog - deadlock or a missed signal"
        )
def _eater(inst, i, n, record):
    def go():
        for _ in range(n):
            inst.wantsToEat(
                i,
                lambda: record([i, 1, 1]),
                lambda: record([i, 2, 1]),
                lambda: record([i, 0, 3]),
                lambda: record([i, 1, 2]),
                lambda: record([i, 2, 2]),
            )
    return go


def drive(cls, args, record):
    inst = cls()
    n = args[0]
    _run([_eater(inst, i, n, record) for i in range(5)])

