def validate(args, events):
    n = args[0]
    forks = [None] * 5
    held = [set() for _ in range(5)]
    eats = [0] * 5
    for e in events:
        if not (isinstance(e, list) and len(e) == 3):
            return False
        a, b, c = e
        if not (0 <= a < 5):
            return False
        if c == 1 or c == 2:
            if b not in (1, 2):
                return False
            fork = a if b == 1 else (a + 1) % 5
            if c == 1:
                if forks[fork] is not None:
                    return False
                forks[fork] = a
                held[a].add(fork)
            else:
                if forks[fork] != a:
                    return False
                forks[fork] = None
                held[a].discard(fork)
        elif c == 3:
            left, right = a, (a + 1) % 5
            if left not in held[a] or right not in held[a]:
                return False
            eats[a] += 1
        else:
            return False
    if any(f is not None for f in forks):
        return False
    return eats == [n] * 5
